export default function ChaseListPanel() {
  const [clients, setClients] = useState([]);
  const [selected, setSelected] = useState(null);
  const [message, setMessage] = useState("");
  const [phase, setPhase] = useState("idle");
  const [sentFor, setSentFor] = useState(null);

  useEffect(() => {
    tools.host_listClients({ filter: "missing" }).then((r) => {
      const sorted = (r.data || []).slice().sort((a, b) => {
        const aMissing = (a.documentsTotal ?? 0) - (a.documentsReceived ?? 0);
        const bMissing = (b.documentsTotal ?? 0) - (b.documentsReceived ?? 0);
        return bMissing - aMissing;
      });
      setClients(sorted);
    });
  }, []);

  const open = (client) => {
    setSelected(client);
    setMessage("");
    setPhase("idle");
  };

  const send = async () => {
    if (!selected || !message.trim()) return;
    setPhase("sending");
    const result = await tools.host_sendClientMessage({
      id: selected.id,
      body: { body: message.trim(), author: "Firm" },
    });
    setPhase(result && result.status === "pending-approval" ? "awaiting" : "sent");
    setSentFor(selected.id);
  };

  const dismiss = () => {
    setSelected(null);
    setPhase("idle");
    setMessage("");
  };

  const token = (name) => `var(--vendo-color-${name})`;
  const radius = (name) => `var(--vendo-radius-${name})`;

  return (
    <div style={{ fontFamily: "var(--vendo-font-family)", color: token("text"), display: "grid", gap: 0 }}>
      {clients.length === 0 && (
        <div style={{ padding: "32px 0", textAlign: "center", color: token("muted"), fontSize: 14 }}>
          No clients with outstanding documents — nothing to chase this week.
        </div>
      )}
      {clients.map((c, i) => {
        const missing = (c.documentsTotal ?? 0) - (c.documentsReceived ?? 0);
        const ratio = c.documentsTotal > 0 ? (c.documentsReceived ?? 0) / c.documentsTotal : 0;
        const pct = Math.round(ratio * 100);
        const isSelected = selected && selected.id === c.id;
        const wasSent = sentFor === c.id && phase === "sent";
        const isAwaiting = sentFor === c.id && phase === "awaiting";

        const urgencyColor = missing >= 5 ? token("danger") : missing >= 2 ? "#b45309" : token("muted");

        return (
          <div key={c.id} style={{
            borderBottom: `1px solid ${token("border")}`,
            background: isSelected ? "#f7f6f3" : token("surface"),
            transition: "background 0.15s",
          }}>
            <div style={{
              display: "grid",
              gridTemplateColumns: "1fr auto auto",
              alignItems: "center",
              gap: 16,
              padding: "14px 20px",
              cursor: "pointer",
            }} onClick={() => isSelected ? dismiss() : open(c)}>
              <div style={{ display: "grid", gap: 4 }}>
                <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                  <span style={{ fontWeight: 600, fontSize: 15 }}>{c.name}</span>
                  {c.entityType && (
                    <span style={{ fontSize: 12, color: token("muted"), background: token("border"), borderRadius: 4, padding: "1px 7px" }}>
                      {c.entityType}
                    </span>
                  )}
                  {c.assignedStaff && (
                    <span style={{ fontSize: 12, color: token("muted") }}>{c.assignedStaff}</span>
                  )}
                </div>
                <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                  <div style={{ width: 120, height: 5, background: token("border"), borderRadius: 99, overflow: "hidden" }}>
                    <div style={{ width: `${pct}%`, height: "100%", background: pct === 100 ? "#16a34a" : token("accent"), borderRadius: 99 }}/>
                  </div>
                  <span style={{ fontSize: 12, color: token("muted") }}>
                    {c.documentsReceived ?? 0} of {c.documentsTotal ?? 0} collected
                  </span>
                </div>
              </div>
              <div style={{ textAlign: "right" }}>
                <span style={{ fontWeight: 700, fontSize: 18, color: urgencyColor }}>{missing}</span>
                <span style={{ fontSize: 12, color: token("muted"), display: "block" }}>missing</span>
              </div>
              <div style={{ display: "flex", flexDirection: "column", alignItems: "flex-end", gap: 4 }}>
                {c.filingDeadline && (
                  <span style={{ fontSize: 12, color: token("muted") }}>
                    Due <strong>{new Date(c.filingDeadline).toLocaleDateString("en-US", { month: "short", day: "numeric" })}</strong>
                  </span>
                )}
                {wasSent && (
                  <span style={{ fontSize: 12, color: "#16a34a", fontWeight: 600 }}>✓ Reminder sent</span>
                )}
                {isAwaiting && (
                  <span style={{ fontSize: 12, color: "#b45309", fontWeight: 600 }}>Awaiting approval…</span>
                )}
              </div>
            </div>

            {isSelected && (
              <div style={{
                padding: "0 20px 18px 20px",
                display: "grid",
                gap: 10,
              }}>
                <div style={{ fontSize: 13, color: token("muted"), fontWeight: 500 }}>
                  Send a reminder to {c.name}
                </div>
                <textarea
                  rows={3}
                  value={message}
                  placeholder={`Hi ${c.name}, we're still waiting on ${missing} document${missing !== 1 ? "s" : ""} to complete your filing. Please upload them at your earliest convenience.`}
                  onChange={(e) => setMessage(e.target.value)}
                  disabled={phase === "sending" || phase === "awaiting" || phase === "sent"}
                  style={{
                    width: "100%",
                    boxSizing: "border-box",
                    padding: "10px 12px",
                    fontSize: 14,
                    fontFamily: "var(--vendo-font-family)",
                    border: `1px solid ${token("border")}`,
                    borderRadius: radius("small"),
                    background: token("surface"),
                    color: token("text"),
                    resize: "vertical",
                    outline: "none",
                  }}
                />
                <div style={{ display: "flex", gap: 8 }}>
                  <button
                    onClick={send}
                    disabled={!message.trim() || phase !== "idle"}
                    style={{
                      padding: "8px 18px",
                      fontSize: 14,
                      fontWeight: 600,
                      background: (!message.trim() || phase !== "idle") ? token("border") : token("accent"),
                      color: (!message.trim() || phase !== "idle") ? token("muted") : token("accentText"),
                      border: "none",
                      borderRadius: radius("small"),
                      cursor: (!message.trim() || phase !== "idle") ? "not-allowed" : "pointer",
                      transition: "background 0.15s",
                    }}
                  >
                    {phase === "sending" ? "Sending…" : phase === "awaiting" ? "Awaiting approval…" : phase === "sent" ? "Sent" : "Send reminder"}
                  </button>
                  <button
                    onClick={dismiss}
                    style={{
                      padding: "8px 14px",
                      fontSize: 14,
                      background: "transparent",
                      color: token("muted"),
                      border: `1px solid ${token("border")}`,
                      borderRadius: radius("small"),
                      cursor: "pointer",
                    }}
                  >
                    Cancel
                  </button>
                </div>
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}
